public String modifyString(String s) {
    char[] result = s.toCharArray();
    for (int i = 0; i < result.length; i++) {
        if (result[i] == '?') {
            for (char c = 'a'; c <= 'z'; c++) {
                if ((i - 1 < 0 || result[i - 1] != c) && (i + 1 >= result.length || result[i + 1] != c)) {
                    result[i] = c;
                    break;
                }
            }
        }
    }
    return new String(result);
}
```


